#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <stdbool.h>

// BFS 队列（数组模拟）
typedef struct {
    int* data;
    int front, rear, cap;
} Queue;

static void qInit(Queue* q, int cap) {
    q->data = (int*)malloc(cap * sizeof(int));
    q->front = q->rear = 0;
}
static void qPush(Queue* q, int v) { q->data[q->rear++] = v; }
static int qPop(Queue* q) { return q->data[q->front++]; }
static bool qEmpty(Queue* q) { return q->front == q->rear; }
static void qFree(Queue* q) { free(q->data); }

// 判定一组互斥图是否可二染色（二分图）
static bool isBipartite(int n, int** edges, int edgesSize) {
    // 自环：资源不能和自己互斥
    for (int i = 0; i < edgesSize; i++)
        if (edges[i][0] == edges[i][1]) return false;

    // 统计度数用于分配邻接表
    int* deg = (int*)calloc(n + 2, sizeof(int));
    for (int i = 0; i < edgesSize; i++) {
        deg[edges[i][0]]++;
        deg[edges[i][1]]++;
    }

    // 邻接表：紧凑数组
    int** adj = (int**)malloc((n + 2) * sizeof(int*));
    int* adjLen = (int*)calloc(n + 2, sizeof(int));
    for (int i = 1; i <= n; i++)
        adj[i] = (int*)malloc(deg[i] * sizeof(int));

    for (int i = 0; i < edgesSize; i++) {
        int u = edges[i][0], v = edges[i][1];
        adj[u][adjLen[u]++] = v;
        adj[v][adjLen[v]++] = u;
    }

    // 染色数组 -1 未染，0/1 两种颜色
    int* color = (int*)malloc((n + 2) * sizeof(int));
    memset(color, -1, (n + 2) * sizeof(int));

    Queue q;
    qInit(&q, n + 2);
    bool ok = true;

    for (int s = 1; s <= n && ok; s++) {
        if (color[s] != -1 || deg[s] == 0) continue;
        color[s] = 0;
        qPush(&q, s);
        while (!qEmpty(&q) && ok) {
            int u = qPop(&q);
            for (int i = 0; i < adjLen[u]; i++) {
                int v = adj[u][i];
                if (color[v] == -1) {
                    // 互斥边两端必须异色
                    color[v] = 1 - color[u];
                    qPush(&q, v);
                } else if (color[v] == color[u]) {
                    // 同色相邻 → 奇环，不是二分图
                    ok = false;
                    break;
                }
            }
        }
        q.front = q.rear = 0;
    }

    // 释放内存
    for (int i = 1; i <= n; i++) free(adj[i]);
    free(adj);
    free(adjLen);
    free(deg);
    free(color);
    qFree(&q);

    return ok;
}

int* canIsolateWithTwoPools(int* resourceCount, int resourceCountSize, int*** conflicts, int* conflictsSizes, int* returnSize) {
    int* ans = (int*)malloc(resourceCountSize * sizeof(int));
    for (int i = 0; i < resourceCountSize; i++)
        ans[i] = isBipartite(resourceCount[i], conflicts[i], conflictsSizes[i]) ? 1 : 0;
    *returnSize = resourceCountSize;
    return ans;
}
